# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

import strawberry
from strawberry import auto
from strawberry.fastapi import GraphQLRouter
from fastapi import FastAPI
from sqlalchemy import create_engine, Column, Integer, String, Float, Text, DateTime, ForeignKey, Table
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship
from datetime import datetime

Base = declarative_base()

# Association table for many-to-many relationship between products and categories
product_category_association = Table(
    'product_category',
    Base.metadata,
    Column('product_id', Integer, ForeignKey('products.id')),
    Column('category_id', Integer, ForeignKey('categories.id'))
)

class Product(Base):
    __tablename__ = 'products'
    
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    description = Column(Text)
    price = Column(Float)
    created_at = Column(DateTime, default=datetime.utcnow)
    
    # Relationships
    reviews = relationship("Review", back_populates="product")
    sellers = relationship("Seller", back_populates="product")
    categories = relationship("Category", secondary=product_category_association, back_populates="products")
    images = relationship("Image", back_populates="product")

class Review(Base):
    __tablename__ = 'reviews'
    
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    author = Column(String)
    rating = Column(Integer)
    comment = Column(Text)
    created_at = Column(DateTime, default=datetime.utcnow)
    
    product = relationship("Product", back_populates="reviews")

class Seller(Base):
    __tablename__ = 'sellers'
    
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    name = Column(String)
    email = Column(String)
    phone = Column(String)
    
    product = relationship("Product", back_populates="sellers")

class Category(Base):
    __tablename__ = 'categories'
    
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, unique=True, index=True)
    
    products = relationship("Product", secondary=product_category_association, back_populates="categories")

class Image(Base):
    __tablename__ = 'images'
    
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    url = Column(String)
    alt_text = Column(String)
    
    product = relationship("Product", back_populates="images")

# SQLAlchemy setup
DATABASE_URL = "sqlite:///./test.db"
engine = create_engine(DATABASE_URL)
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

Base.metadata.create_all(bind=engine)

# Strawberry Types
@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    created_at: datetime
    reviews: list["ReviewType"]
    sellers: list["SellerType"]
    categories: list["CategoryType"]
    images: list["ImageType"]

@strawberry.type
class ReviewType:
    id: int
    product_id: int
    author: str
    rating: int
    comment: str
    created_at: datetime

@strawberry.type
class SellerType:
    id: int
    product_id: int
    name: str
    email: str
    phone: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    product_id: int
    url: str
    alt_text: str

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType:
        db = SessionLocal()
        try:
            return db.query(Product).filter(Product.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def products(self, info) -> list[ProductType]:
        db = SessionLocal()
        try:
            return db.query(Product).all()
        finally:
            db.close()
    
    @strawberry.field
    def review(self, info, id: int) -> ReviewType:
        db = SessionLocal()
        try:
            return db.query(Review).filter(Review.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def seller(self, info, id: int) -> SellerType:
        db = SessionLocal()
        try:
            return db.query(Seller).filter(Seller.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def category(self, info, id: int) -> CategoryType:
        db = SessionLocal()
        try:
            return db.query(Category).filter(Category.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def image(self, info, id: int) -> ImageType:
        db = SessionLocal()
        try:
            return db.query(Image).filter(Image.id == id).first()
        finally:
            db.close()

schema = strawberry.Schema(query=Query)
graphql_app = GraphQLRouter(schema)
app = FastAPI()
app.include_router(graphql_app, prefix="/graphql")